theory.code:
schema = {
    "type": "object",
    "properties": {
        "name": {"type": "string"},
        "email": {"type": "string"},
        "plan": {"type": "string", "enum": ["free", "pro", "enterprise"]},
        "demo_requested": {"type": "boolean"},
    },
    "required": ["name", "email", "plan", "demo_requested"],
    "additionalProperties": False,
}

message = client.messages.create(
    model="claude-opus-4-8",
    max_tokens=1024,
    output_config={"format": {"type": "json_schema", "schema": schema}},
    messages=[{
        "role": "user",
        "content": "Lead: Anna Kim (anna@corp.com) wants the Pro plan and is asking for a demo.",
    }],
)

import json
data = json.loads(message.content[0].text)  # always parses
print(data["plan"])  # "pro"

import { z } from "zod";
import { zodOutputFormat } from "@anthropic-ai/sdk/helpers/zod";

const Lead = z.object({
  name: z.string(),
  email: z.string(),
  plan: z.enum(["free", "pro", "enterprise"]),
  demo_requested: z.boolean(),
});

const response = await client.messages.parse({
  model: "claude-opus-4-8",
  max_tokens: 1024,
  output_config: { format: zodOutputFormat(Lead) },
  messages: [{ role: "user", content: "Lead: Anna Kim (anna@corp.com), Pro plan, asking for a demo." }],
});

console.log(response.parsed_output?.plan); // typed: "free" | "pro" | "enterprise"

steps.claudeReply:
Good set! Here's the schema based on your description:

```json
{
  "type": "object",
  "properties": {
    "name": {"type": "string"},
    "email": {"type": "string"},
    "years_of_experience": {"type": "integer"},
    "skills": {"type": "array", "items": {"type": "string"}},
    "level": {"type": "string", "enum": ["junior", "middle", "senior"]}
  },
  "required": ["name", "level"],
  "additionalProperties": false
}
```

Notice `level`: without an enum the model would write "senior", "Senior+", "experienced" — and your filtering by level would fall apart. With an enum there are exactly three options. What happens if a resume has no email?
